function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
  const rows = grid.length;
  if (rows === 0) return null;
  const cols = grid[0].length;
  if (cols === 0) return null;

  const [startR, startC] = start;
  const [endR, endC] = end;

  if (startR < 0 || startR >= rows || startC < 0 || startC >= cols ||
      endR < 0 || endR >= rows || endC < 0 || endC >= cols) {
    return null;
  }

  if (grid[startR][startC] === 1 || grid[endR][endC] === 1) {
    return null;
  }

  class MinHeap {
    data: [number, number, number, number][] = [];
    push(val: [number, number, number, number]) {
      this.data.push(val);
      let idx = this.data.length - 1;
      while (idx > 0) {
        let p = (idx - 1) >> 1;
        if (this.data[p][0] <= this.data[idx][0]) break;
        [this.data[p], this.data[idx]] = [this.data[idx], this.data[p]];
        idx = p;
      }
    }
    pop() {
      if (this.data.length === 0) return null;
      const res = this.data[0];
      const last = this.data.pop()!;
      if (this.data.length > 0) {
        this.data[0] = last;
        let idx = 0;
        while (true) {
          let l = (idx << 1) + 1, r = (idx << 1) + 2, s = idx;
          if (l < this.data.length && this.data[l][0] < this.data[s][0]) s = l;
          if (r < this.data.length && this.data[r][0] < this.data[s][0]) s = r;
          if (s === idx) break;
          [this.data[s], this.data[idx]] = [this.data[idx], this.data[s]];
          idx = s;
        }
      }
      return res;
    }
    size() { return this.data.length; }
  }

  const h = (r: number, c: number) => Math.abs(r - endR) + Math.abs(c - endC);
  const dist = Array.from({ length: rows }, () => Array(cols).fill(Infinity));
  const pq = new MinHeap();

  dist[startR][startC] = 0;
  pq.push([h(startR, startC), 0, startR, startC]);

  const dirs = [[0, 1], [0, -1], [1, 0], [-1, 0]];

  while (pq.size() > 0) {
    const node = pq.pop();
    if (!node) break;
    const [f, g, r, c] = node;

    if (r === endR && c === endC) return g;
    if (g > dist[r][c]) continue;

    for (const [dr, dc] of dirs) {
      const nr = r + dr;
      const nc = c + dc;

      if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] === 0) {
        const newG = g + 1;
        if (newG < dist[nr][nc]) {
          dist[nr][nc] = newG;
          pq.push([newG + h(nr, nc), newG, nr, nc]);
        }
      }
    }
  }

  return null;
}

function binarySearchBoundary(values: number[], target: number): number {
  let low = 0;
  let high = values.length - 1;
  let result = -1;

  while (low <= high) {
    const mid = Math.floor(low + (high - low) / 2);

    if (values[mid] === target) {
      result = mid;
      high = mid - 1;
    } else if (values[mid] < target) {
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }

  return result;
}

function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
  const findBound = (isFirst: boolean): number => {
    let low = 0;
    let high = values.length - 1;
    let result = -1;

    while (low <= high) {
      const mid = Math.floor(low + (high - low) / 2);
      if (values[mid] === target) {
        result = mid;
        if (isFirst) {
          high = mid - 1;
        } else {
          low = mid + 1;
        }
      } else if (values[mid] < target) {
        low = mid + 1;
      } else {
        high = mid - 1;
      }
    }
    return result;
  };

  const firstIndex = findBound(true);
  if (firstIndex === -1) return [-1, -1];
  const lastIndex = findBound(false);

  return [firstIndex, lastIndex];
}

function dijkstraShortestPath(nodeCount: number, edges: readonly (readonly [number, number, number])[], start: number, end: number): number | null {
  const adj: [number, number][][] = Array.from({ length: nodeCount }, () => []);
  for (const [u, v, w] of edges) {
    adj[u].push([v, w]);
  }

  const distances = new Float64Array(nodeCount).fill(Infinity);
  distances[start] = 0;

  const pq: [number, number][] = [];
  const push = (val: [number, number]) => {
    pq.push(val);
    let idx = pq.length - 1;
    while (idx > 0) {
      let parent = (idx - 1) >> 1;
      if (pq[idx][0] >= pq[parent][0]) break;
      [pq[idx], pq[parent]] = [pq[parent], pq[idx]];
      idx = parent;
    }
  };

  const pop = (): [number, number] | undefined => {
    if (pq.length === 0) return undefined;
    const top = pq[0];
    const bottom = pq.pop()!;
    if (pq.length > 0) {
      pq[0] = bottom;
      let idx = 0;
      while (true) {
        let left = (idx << 1) + 1;
        let right = (idx << 1) + 2;
        let smallest = idx;
        if (left < pq.length && pq[left][0] < pq[smallest][0]) smallest = left;
        if (right < pq.length && pq[right][0] < pq[smallest][0]) smallest = right;
        if (smallest === idx) break;
        [pq[idx], pq[smallest]] = [pq[smallest], pq[idx]];
        idx = smallest;
      }
    }
    return top;
  };

  push([0, start]);

  while (pq.length > 0) {
    const current = pop();
    if (!current) break;
    const [d, u] = current;

    if (d > distances[u]) continue;
    if (u === end) return d;

    for (const [v, weight] of adj[u]) {
      if (distances[u] + weight < distances[v]) {
        distances[v] = distances[u] + weight;
        push([distances[v], v]);
      }
    }
  }

  return distances[end] === Infinity ? null : distances[end];
}

function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
  // Trim leading zeros and handle empty inputs
  const trim = (arr: number[]) => {
    let start = 0;
    while (start < arr.length - 1 && arr[start] === 0) start++;
    return start === 0 ? [...arr] : arr.slice(start);
  };

  let aTrimmed = trim(a.length === 0 ? [0] : a);
  let bTrimmed = trim(b.length === 0 ? [0] : b);

  if ((aTrimmed.length === 1 && aTrimmed[0] === 0) || (bTrimmed.length === 1 && bTrimmed[0] === 0)) {
    return [0];
  }

  // Reverse to little-endian for polynomial multiplication
  const revA = [...aTrimmed].reverse();
  const revB = [...bTrimmed].reverse();

  let n = 1;
  while (n < revA.length + revB.length) n <<= 1;

  const reA = new Float64Array(n);
  const imA = new Float64Array(n);
  const reB = new Float64Array(n);
  const imB = new Float64Array(n);

  for (let i = 0; i < revA.length; i++) reA[i] = revA[i];
  for (let i = 0; i < revB.length; i++) reB[i] = revB[i];

  function fft(re: Float64Array, im: Float64Array, invert: boolean) {
    for (let i = 1, j = 0; i < n; i++) {
      let bit = n >> 1;
      for (; j & bit; bit >>= 1) j ^= bit;
      j ^= bit;
      if (i < j) {
        [re[i], re[j]] = [re[j], re[i]];
        [im[i], im[j]] = [im[j], im[i]];
      }
    }

    for (let len = 2; len <= n; len <<= 1) {
      const ang = (2 * Math.PI / len) * (invert ? -1 : 1);
      const wlenRe = Math.cos(ang);
      const wlenIm = Math.sin(ang);
      for (let i = 0; i < n; i += len) {
        let wRe = 1, wIm = 0;
        for (let j = 0; j < len / 2; j++) {
          const uRe = re[i + j], uIm = im[i + j];
          const vRe = re[i + j + len / 2] * wRe - im[i + j + len / 2] * wIm;
          const vIm = re[i + j + len / 2] * wIm + im[i + j + len / 2] * wRe;
          re[i + j] = uRe + vRe;
          im[i + j] = uIm + vIm;
          re[i + j + len / 2] = uRe - vRe;
          im[i + j + len / 2] = uIm - vIm;
          const nextWRe = wRe * wlenRe - wIm * wlenIm;
          wIm = wRe * wlenIm + wIm * wlenRe;
          wRe = nextWRe;
        }
      }
    }

    if (invert) {
      for (let i = 0; i < n; i++) {
        re[i] /= n;
        im[i] /= n;
      }
    }
  }

  fft(reA, imA, false);
  fft(reB, imB, false);

  const reC = new Float64Array(n);
  const imC = new Float64Array(n);
  for (let i = 0; i < n; i++) {
    reC[i] = reA[i] * reB[i] - imA[i] * imB[i];
    imC[i] = reA[i] * imB[i] + imA[i] * reB[i];
  }

  fft(reC, imC, true);

  const result: number[] = [];
  let carry = 0;
  for (let i = 0; i < n; i++) {
    const val = Math.round(reC[i]) + carry;
    result.push(val % 10);
    carry = Math.floor(val / 10);
  }
  while (carry) {
    result.push(carry % 10);
    carry = Math.floor(carry / 10);
  }

  while (result.length > 1 && result[result.length - 1] === 0) {
    result.pop();
  }

  return result.reverse();
}

function fibonacci(n: number): number {
  if (n <= 0) return 0;
  if (n === 1) return 1;

  let a = 0;
  let b = 1;

  for (let i = 2; i <= n; i++) {
    const temp = a + b;
    a = b;
    b = temp;
  }

  return b;
}

function groupAnagrams(words: string[]): string[][] {
  const groups = new Map<string, string[]>();

  for (const word of words) {
    const sorted = word.split('').sort().join('');
    if (!groups.has(sorted)) {
      groups.set(sorted, []);
    }
    groups.get(sorted)!.push(word);
  }

  return Array.from(groups.values());
}

function longestCommonSubsequence(a: string, b: string): number {
  const m = a.length;
  const n = b.length;
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (a[i - 1] === b[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1] + 1;
      } else {
        dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
      }
    }
  }

  return dp[m][n];
}

function longestSubstringNoRepeat(input: string): number {
  let maxLength = 0;
  let start = 0;
  const charMap = new Map<string, number>();

  for (let end = 0; end < input.length; end++) {
    const char = input[end];
    if (charMap.has(char)) {
      start = Math.max(start, charMap.get(char)! + 1);
    }
    charMap.set(char, end);
    maxLength = Math.max(maxLength, end - start + 1);
  }

  return maxLength;
}

function lruCache(capacity: number, operations: readonly (readonly ['get' | 'put', number, number?])[]): (number | null)[] {
  const cache = new Map<number, number>();
  const results: (number | null)[] = [];

  for (const op of operations) {
    const [type, key, value] = op;

    if (type === 'get') {
      if (cache.has(key)) {
        const val = cache.get(key)!;
        cache.delete(key);
        cache.set(key, val);
        results.push(val);
      } else {
        results.push(null);
      }
    } else if (type === 'put') {
      if (cache.has(key)) {
        cache.delete(key);
      }
      cache.set(key, value!);
      if (cache.size > capacity) {
        const firstKey = cache.keys().next().value;
        cache.delete(firstKey);
      }
      results.push(null);
    }
  }

  return results;
}

function mergeIntervals(intervals: [number, number][]): [number, number][] {
  if (intervals.length <= 1) return [...intervals];

  const sorted = [...intervals].sort((a, b) => a[0] - b[0]);
  const merged: [number, number][] = [];

  let currentInterval = sorted[0];
  merged.push(currentInterval);

  for (let i = 1; i < sorted.length; i++) {
    const nextInterval = sorted[i];

    if (nextInterval[0] <= currentInterval[1]) {
      currentInterval[1] = Math.max(currentInterval[1], nextInterval[1]);
    } else {
      currentInterval = nextInterval;
      merged.push(currentInterval);
    }
  }

  return merged;
}

function mergeSortLinkedList(head: {value: number; next: any} | null): {value: number; next: any} | null {
  if (!head || !head.next) {
    return head;
  }

  // Split the list into two halves
  let slow = head;
  let fast = head.next;

  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
  }

  const mid = slow.next;
  slow.next = null;

  // Recursively sort both halves
  const left = mergeSortLinkedList(head);
  const right = mergeSortLinkedList(mid);

  // Merge the sorted halves
  return merge(left, right);
}

function merge(l1: {value: number; next: any} | null, l2: {value: number; next: any} | null): {value: number; next: any} | null {
  const dummy = { value: 0, next: null as any };
  let current = dummy;

  while (l1 && l2) {
    if (l1.value <= l2.value) {
      current.next = l1;
      l1 = l1.next;
    } else {
      current.next = l2;
      l2 = l2.next;
    }
    current = current.next;
  }

  current.next = l1 || l2;
  return dummy.next;
}

function minStack(operations: readonly (readonly ['push' | 'pop' | 'top' | 'getMin', number?])[]): (number | null)[] {
  const stack: number[] = [];
  const minStack: number[] = [];
  const results: (number | null)[] = [];

  for (const [op, val] of operations) {
    switch (op) {
      case 'push':
        if (val !== undefined) {
          stack.push(val);
          const currentMin = minStack.length === 0 ? val : Math.min(val, minStack[minStack.length - 1]);
          minStack.push(currentMin);
        }
        break;
      case 'pop':
        stack.pop();
        minStack.pop();
        break;
      case 'top':
        results.push(stack.length === 0 ? null : stack[stack.length - 1]);
        break;
      case 'getMin':
        results.push(minStack.length === 0 ? null : minStack[minStack.length - 1]);
        break;
    }
  }

  return results;
}

function numberOfIslands(grid: string[][]): number {
  if (!grid || grid.length === 0) return 0;

  const rows = grid.length;
  const cols = grid[0].length;
  let count = 0;

  const dfs = (r: number, c: number) => {
    if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] === '0') {
      return;
    }

    grid[r][c] = '0';

    dfs(r + 1, c);
    dfs(r - 1, c);
    dfs(r, c + 1);
    dfs(r, c - 1);
  };

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (grid[r][c] === '1') {
        count++;
        dfs(r, c);
      }
    }
  }

  return count;
}

function productOfArrayExceptSelf(values: number[]): number[] {
  const n = values.length;
  if (n === 0) return [];

  const result: number[] = new Array(n).fill(1);

  let leftProduct = 1;
  for (let i = 0; i < n; i++) {
    result[i] = leftProduct;
    leftProduct *= values[i];
  }

  let rightProduct = 1;
  for (let i = n - 1; i >= 0; i--) {
    result[i] *= rightProduct;
    rightProduct *= values[i];
  }

  return result;
}

function quickselectKthSmallest(values: number[], k: number): number {
  const nums = [...values];
  const targetIndex = k - 1;

  function partition(left: number, right: number): number {
    const pivot = nums[right];
    let i = left;
    for (let j = left; j < right; j++) {
      if (nums[j] < pivot) {
        [nums[i], nums[j]] = [nums[j], nums[i]];
        i++;
      }
    }
    [nums[i], nums[right]] = [nums[right], nums[i]];
    return i;
  }

  let left = 0;
  let right = nums.length - 1;

  while (left <= right) {
    const pivotIndex = partition(left, right);
    if (pivotIndex === targetIndex) {
      return nums[pivotIndex];
    } else if (pivotIndex < targetIndex) {
      left = pivotIndex + 1;
    } else {
      right = pivotIndex - 1;
    }
  }

  throw new Error("Index out of bounds");
}

function quicksort(arr: number[]): number[] {
  if (arr.length <= 1) {
    return [...arr];
  }

  const pivot = arr[Math.floor(arr.length / 2)];
  const left = arr.filter(x => x < pivot);
  const middle = arr.filter(x => x === pivot);
  const right = arr.filter(x => x > pivot);

  return [...quicksort(left), ...middle, ...quicksort(right)];
}

function topKFrequent(values: number[], k: number): number[] {
  const freqMap = new Map<number, number>();
  for (const val of values) {
    freqMap.set(val, (freqMap.get(val) || 0) + 1);
  }

  return Array.from(freqMap.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, k)
    .map(([val]) => val);
}

function toyRsaBigint(p: bigint, q: bigint, e: bigint, message: bigint): {publicKey: {n: bigint; e: bigint}; privateKey: {n: bigint; d: bigint}; cipher: bigint; decrypted: bigint} {
  const n = p * q;
  const phi = (p - 1n) * (q - 1n);

  const modInverse = (a: bigint, m: bigint): bigint => {
    let m0 = m;
    let y = 0n, x = 1n;
    if (m === 1n) return 0n;
    while (a > 1n) {
      if (m === 0n) break;
      let q = a / m;
      let t = m;
      m = a % m;
      a = t;
      t = y;
      y = x - q * y;
      x = t;
    }
    if (x < 0n) x += m0;
    return x;
  };

  const power = (base: bigint, exp: bigint, mod: bigint): bigint => {
    let res = 1n;
    base = base % mod;
    while (exp > 0n) {
      if (exp % 2n === 1n) res = (res * base) % mod;
      base = (base * base) % mod;
      exp = exp / 2n;
    }
    return res;
  };

  const d = modInverse(e, phi);
  const cipher = power(message, e, n);
  const decrypted = power(cipher, d, n);

  return {
    publicKey: { n, e },
    privateKey: { n, d },
    cipher,
    decrypted
  };
}

function twoSum(nums: number[], target: number): [number, number] | null {
  const map = new Map<number, number>();
  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];
    if (map.has(complement)) {
      return [map.get(complement)!, i];
    }
    map.set(nums[i], i);
  }
  return null;
}

function unionFindConnectedComponentsOnline(n: number, operations: readonly (readonly [number, number])[]): number[] {
  const parent = new Int32Array(n);
  for (let i = 0; i < n; i++) {
    parent[i] = i;
  }

  const find = (i: number): number => {
    let root = i;
    while (parent[root] !== root) {
      root = parent[root];
    }
    while (parent[i] !== root) {
      const next = parent[i];
      parent[i] = root;
      i = next;
    }
    return root;
  };

  let components = n;
  const result: number[] = [];

  for (const [u, v] of operations) {
    const rootU = find(u);
    const rootV = find(v);
    if (rootU !== rootV) {
      parent[rootU] = rootV;
      components--;
    }
    result.push(components);
  }

  return result;
}

function validParentheses(input: string): boolean {
  const stack: string[] = [];
  const pairs: { [key: string]: string } = {
    ')': '(',
    ']': '[',
    '}': '{',
  };

  for (const char of input) {
    if (char === '(' || char === '[' || char === '{') {
      stack.push(char);
    } else if (char === ')' || char === ']' || char === '}') {
      if (stack.length === 0 || stack.pop() !== pairs[char]) {
        return false;
      }
    }
  }

  return stack.length === 0;
}

function integerBreakMaxProduct(n: number): number {
  if (n === 2) return 1;
  if (n === 3) return 2;

  let product = 1;
  while (n > 4) {
    product *= 3;
    n -= 3;
  }
  return product * n;
}

function avlTreeInsertRebalance(values: number[]): {value: number; height: number; left: any; right: any} | null {
  type AVLNode = {
    value: number;
    height: number;
    left: AVLNode | null;
    right: AVLNode | null;
  };

  function getHeight(node: AVLNode | null): number {
    return node ? node.height : 0;
  }

  function updateHeight(node: AVLNode): void {
    node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
  }

  function getBalance(node: AVLNode | null): number {
    return node ? getHeight(node.left) - getHeight(node.right) : 0;
  }

  function rotateRight(y: AVLNode): AVLNode {
    const x = y.left!;
    const T2 = x.right;
    x.right = y;
    y.left = T2;
    updateHeight(y);
    updateHeight(x);
    return x;
  }

  function rotateLeft(x: AVLNode): AVLNode {
    const y = x.right!;
    const T2 = y.left;
    y.left = x;
    x.right = T2;
    updateHeight(x);
    updateHeight(y);
    return y;
  }

  function insert(node: AVLNode | null, value: number): AVLNode {
    if (!node) {
      return { value, height: 1, left: null, right: null };
    }

    if (value < node.value) {
      node.left = insert(node.left, value);
    } else if (value > node.value) {
      node.right = insert(node.right, value);
    } else {
      return node; // Ignore duplicates
    }

    updateHeight(node);
    const balance = getBalance(node);

    // Left Left Case
    if (balance > 1 && value < (node.left as AVLNode).value) {
      return rotateRight(node);
    }
    // Right Right Case
    if (balance < -1 && value > (node.right as AVLNode).value) {
      return rotateLeft(node);
    }
    // Left Right Case
    if (balance > 1 && value > (node.left as AVLNode).value) {
      node.left = rotateLeft(node.left as AVLNode);
      return rotateRight(node);
    }
    // Right Left Case
    if (balance < -1 && value < (node.right as AVLNode).value) {
      node.right = rotateRight(node.right as AVLNode);
      return rotateLeft(node);
    }

    return node;
  }

  let root: AVLNode | null = null;
  for (const val of values) {
    root = insert(root, val);
  }
  return root;
}

