function detectCycleDirectedGraph(graph: Record<number, number[]>): boolean {
  const visited = new Set<number>();
  const recStack = new Set<number>();

  function hasCycle(node: number): boolean {
    visited.add(node);
    recStack.add(node);

    const neighbors = graph[node] || [];
    for (const neighbor of neighbors) {
      if (!visited.has(neighbor)) {
        if (hasCycle(neighbor)) return true;
      } else if (recStack.has(neighbor)) {
        return true;
      }
    }

    recStack.delete(node);
    return false;
  }

  const nodes = Object.keys(graph).map(Number);
  for (const node of nodes) {
    if (!visited.has(node)) {
      if (hasCycle(node)) return true;
    }
  }

  return false;
}

function evaluateReversePolishNotation(tokens: string[]): number {
  const stack: number[] = [];

  for (const token of tokens) {
    if (token === '+') {
      const b = stack.pop()!;
      const a = stack.pop()!;
      stack.push(a + b);
    } else if (token === '-') {
      const b = stack.pop()!;
      const a = stack.pop()!;
      stack.push(a - b);
    } else if (token === '*') {
      const b = stack.pop()!;
      const a = stack.pop()!;
      stack.push(a * b);
    } else if (token === '/') {
      const b = stack.pop()!;
      const a = stack.pop()!;
      stack.push(Math.trunc(a / b));
    } else {
      stack.push(Number(token));
    }
  }

  return stack[0];
}

function kLargestElementsInStream(stream: number[], k: number): number[][] {
  const result: number[][] = [];
  const topK: number[] = [];

  for (const num of stream) {
    topK.push(num);
    topK.sort((a, b) => b - a);
    if (topK.length > k) {
      topK.pop();
    }
    result.push([...topK]);
  }

  return result;
}

function reverseLinkedListInPlace(head: {value: number; next: any} | null): {value: number; next: any} | null {
  let prev = null;
  let current = head;
  while (current !== null) {
    const next = current.next;
    current.next = prev;
    prev = current;
    current = next;
  }
  return prev;
}

function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
  class TrieNode {
    children: { [key: string]: TrieNode } = {};
    isEndOfWord: boolean = false;
  }

  const root = new TrieNode();

  for (const word of words) {
    let node = root;
    for (const char of word) {
      if (!node.children[char]) {
        node.children[char] = new TrieNode();
      }
      node = node.children[char];
    }
    node.isEndOfWord = true;
  }

  const results: string[][] = [];

  for (const prefix of prefixes) {
    let node = root;
    let possible = true;
    for (const char of prefix) {
      if (!node.children[char]) {
        possible = false;
        break;
      }
      node = node.children[char];
    }

    if (!possible) {
      results.push([]);
      continue;
    }

    const completions: string[] = [];
    const dfs = (currNode: TrieNode, currWord: string) => {
      if (currNode.isEndOfWord) {
        completions.push(currWord);
      }

      const sortedKeys = Object.keys(currNode.children).sort();
      for (const char of sortedKeys) {
        dfs(currNode.children[char], currWord + char);
      }
    };

    dfs(node, prefix);
    results.push(completions);
  }

  return results;
}

function validateBinarySearchTree(root: {value: number; left: any; right: any} | null): boolean {
  function validate(node: any, min: number | null, max: number | null): boolean {
    if (!node) {
      return true;
    }

    if ((min !== null && node.value <= min) || (max !== null && node.value >= max)) {
      return false;
    }

    return validate(node.left, min, node.value) && validate(node.right, node.value, max);
  }

  return validate(root, null, null);
}

function getISOWeek(date: Date): {week: number; year: number} {
  const target = new Date(date.getTime());
  // ISO 8601: Week 1 is the week with the first Thursday of the year.
  // Move the date to the nearest Thursday.
  target.setUTCDate(target.getUTCDate() + 4 - (target.getUTCDay() || 7));
  const year = target.getUTCFullYear();

  // Find the first Thursday of the ISO year.
  const firstThursday = new Date(Date.UTC(year, 0, 4));
  firstThursday.setUTCDate(firstThursday.getUTCDate() + 4 - (firstThursday.getUTCDay() || 7));

  // Calculate the number of weeks between the first Thursday and the target Thursday.
  const week = Math.round((target.getTime() - firstThursday.getTime()) / 604800000) + 1;

  return { week, year };
}

function validateDate(s: string): boolean {
  const regex = /^\d{4}-\d{2}-\d{2}$/;
  if (!regex.test(s)) return false;

  const [yearStr, monthStr, dayStr] = s.split('-');
  const year = parseInt(yearStr, 10);
  const month = parseInt(monthStr, 10);
  const day = parseInt(dayStr, 10);

  if (month < 1 || month > 12) return false;

  const daysInMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

  if (month === 2) {
    const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
    if (isLeap) {
      daysInMonth[1] = 29;
    }
  }

  return day >= 1 && day <= daysInMonth[month - 1];
}

function murmurhash3(str: string, seed: number): number {
  let h1 = seed | 0;
  const len = str.length;
  const c1 = 0xcc9e2d51;
  const c2 = 0x1b873593;

  for (let i = 0; i < len - 1; i += 2) {
    let k = (str.charCodeAt(i + 1) << 16) | str.charCodeAt(i);
    k = Math.imul(k, c1);
    k = (k << 15) | (k >>> 17);
    k = Math.imul(k, c2);
    h1 ^= k;
    h1 = (h1 << 13) | (h1 >>> 19);
    h1 = (Math.imul(h1, 5) + 0xe6546b64) | 0;
  }

  if (len % 2 === 1) {
    let k1 = str.charCodeAt(len - 1);
    k1 = Math.imul(k1, c1);
    k1 = (k1 << 15) | (k1 >>> 17);
    k1 = Math.imul(k1, c2);
    h1 ^= k1;
  }

  h1 ^= len;
  h1 ^= h1 >>> 16;
  h1 = Math.imul(h1, 0x85ebca6b);
  h1 ^= h1 >>> 13;
  h1 = Math.imul(h1, 0xc2b2ae35);
  h1 ^= h1 >>> 16;

  return h1 >>> 0;
}

function evaluateBooleanExpression(expression: string): boolean {
  let pos = 0;

  const skipWhitespace = () => {
    while (pos < expression.length && /\s/.test(expression[pos])) {
      pos++;
    }
  };

  const parseExpression = (): boolean => {
    let result = parseTerm();
    skipWhitespace();
    while (pos < expression.length && expression.startsWith('||', pos)) {
      pos += 2;
      const right = parseTerm();
      result = result || right;
      skipWhitespace();
    }
    return result;
  };

  const parseTerm = (): boolean => {
    let result = parseFactor();
    skipWhitespace();
    while (pos < expression.length && expression.startsWith('&&', pos)) {
      pos += 2;
      const right = parseFactor();
      result = result && right;
      skipWhitespace();
    }
    return result;
  };

  const parseFactor = (): boolean => {
    skipWhitespace();
    if (pos < expression.length && expression[pos] === '!') {
      pos++;
      return !parseFactor();
    }
    return parsePrimary();
  };

  const parsePrimary = (): boolean => {
    skipWhitespace();
    if (pos < expression.length && expression[pos] === '(') {
      pos++;
      const result = parseExpression();
      skipWhitespace();
      if (pos < expression.length && expression[pos] === ')') {
        pos++;
      }
      return result;
    }

    if (expression.startsWith('true', pos)) {
      pos += 4;
      return true;
    }
    if (expression.startsWith('false', pos)) {
      pos += 5;
      return false;
    }

    throw new Error(`Unexpected character at position ${pos}`);
  };

  return parseExpression();
}

function dateInputToIso(input: string): string | null {
  const regex = /^\d{4}-\d{2}-\d{2}$/;
  if (!regex.test(input)) {
    return null;
  }

  const [yearStr, monthStr, dayStr] = input.split('-');
  const year = parseInt(yearStr, 10);
  const month = parseInt(monthStr, 10);
  const day = parseInt(dayStr, 10);

  if (month < 1 || month > 12) {
    return null;
  }

  const date = new Date(year, month - 1, day);

  if (
    date.getFullYear() === year &&
    date.getMonth() === month - 1 &&
    date.getDate() === day
  ) {
    return input;
  }

  return null;
}

function normalizeNumberInput(input: string | number | null): number | null {
  if (input === null) {
    return null;
  }

  let num: number;

  if (typeof input === 'string') {
    const trimmed = input.trim();
    if (trimmed === '') {
      return null;
    }
    num = Number(trimmed);
  } else {
    num = input;
  }

  return Number.isFinite(num) ? num : null;
}

